import{bQ as r,aL as t,u as a,G as s}from"./chunks/framework.GzqLZJY6.js";const o=JSON.parse('{"title":"写在前面：AeroSmart 项目介绍","description":"AeroSmart 是一款面向航模爱好者与早期原型开发团队的桌面级智能涵道风洞系统。","frontmatter":{"title":"写在前面：AeroSmart 项目介绍","date":"2026-01-27T00:00:00.000Z","description":"AeroSmart 是一款面向航模爱好者与早期原型开发团队的桌面级智能涵道风洞系统。","categories":"项目","tags":["AeroSmart","风洞","Rust"],"top":false,"head":[["link",{"rel":"canonical","href":"https://blog.jiangyin14.top/posts/aerosmart-intro"}]]},"headers":[],"relativePath":"posts/aerosmart-intro.md","filePath":"posts/aerosmart-intro.md","lastUpdated":1772500635000}');const e=r({name:"posts/aerosmart-intro.md"},[["render",function(r,o,e,n,p,m){return t(),a("div",null,[...o[0]||(o[0]=[s('<p>好，那么好，<s><strong>这是个新坑</strong></s>。你也可以认为是 <em>Rust 探索</em> 系列的坑之一。</p><p>AeroSmart 是一款面向航模爱好者与早期原型开发团队的<strong>桌面级智能涵道风洞系统</strong>。项目旨在在 CFD 流体仿真与真实飞行测试之间，提供一种<strong>低成本、可重复、工程级的中间验证工具</strong>，用于辅助设计方案的筛选与迭代优化。</p><p>系统采用<strong>双涵道风扇驱动的模块化风洞结构</strong>，可在小尺度测试段内生成<strong>稳定、可控的高速气流</strong>，并通过皮托管、声学传感器等多源传感手段，实现对风速及气流状态的实时监测。结合 PID 闭环控制与自动化实验流程，用户能够在一致的气动条件下，对不同外形或结构方案进行快速、可对比的测试与评估。在此基础上，系统进一步引入 AI 分析模块，根据模型在风洞中的气动表现与实验数据，辅助提出针对性的结构或外形<strong>改进建议</strong>，从而提升设计迭代效率。</p><p>本系列的文档是对 AeroSmart 的<a href="./aerosmart-tech-specs">技术设定</a>的进一步探索与分析，同时，相关的页面与帖子使用<code>Obsidian</code> 进行编辑，全部页面将上传到 <em>姜胤的 Blog</em> 中。前端渲染使用了不一样的 Handler ，所以会出现部分无法正确识别的情况，请见谅。</p><p>好，那么好，让我们开始吧。</p><hr><p>我在本项目中目前负责的是上位机和部分数据处理与分析逻辑的编写，接下来将要迎来的是第一部分：<a href="./aerosmart-audio-analysis">怎么让音频信息有用</a></p>',7)])])}]]);export{o as __pageData,e as default};
